using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// ─── Configuration ──────────────────────────────────────────────────────────────

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

// ─── Build IChatClient (MEAI abstraction over OpenAI) ───────────────────────────

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// ─── Register tools ─────────────────────────────────────────────────────────────

var notes = new NoteStore();
var search = new WebSearcher();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(search.SearchAsync),
    AIFunctionFactory.Create(search.FetchPageAsync),
    AIFunctionFactory.Create(notes.SaveNote),
    AIFunctionFactory.Create(notes.GetNotes),
};

// ─── Create the research agent ──────────────────────────────────────────────────

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your goal is to thoroughly research a given topic
        using web search and note-taking tools.

        Follow this workflow:
        1. Search the web for the topic to get an overview.
        2. Fetch one or two of the most relevant pages for deeper detail.
        3. Save key findings as notes using the SaveNote tool.
        4. Perform follow-up searches to fill knowledge gaps or explore subtopics.
        5. Once you have enough material, retrieve your notes with GetNotes and
           produce a well-structured summary organized by theme.

        Always cite source URLs when possible. Be thorough but concise.
        """,
    name: "Researcher",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools: tools);

// ─── Get the research topic ─────────────────────────────────────────────────────

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");
Console.WriteLine("─── Agent Working ─────────────────────────────────────────\n");

// ─── Run the agent ──────────────────────────────────────────────────────────────

using var session = await agent.CreateSessionAsync("research-session");

var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions { Temperature = 0f },
};

await foreach (var update in agent.RunStreamingAsync(
    $"""
    Research the following topic and provide a comprehensive summary:

    **{topic}**

    Search the web, take notes on key findings, and then produce a final
    structured summary with sections and source citations.
    """,
    session,
    runOptions))
{
    if (!string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine("\n\n─── Research Complete ──────────────────────────────────────");

// ═════════════════════════════════════════════════════════════════════════════════
// Tool implementations
// ═════════════════════════════════════════════════════════════════════════════════

/// <summary>Stores and retrieves research notes the agent accumulates.</summary>
public sealed class NoteStore
{
    private readonly List<string> _notes = [];

    [Description("Save a research note with key findings, facts, or insights discovered during research.")]
    public string SaveNote(
        [Description("The note content to save")] string content)
    {
        _notes.Add(content);
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all saved research notes so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
            sb.AppendLine($"--- Note #{i + 1} ---").AppendLine(_notes[i]).AppendLine();

        return sb.ToString();
    }
}

/// <summary>Provides web search and page-fetching capabilities.</summary>
public sealed class WebSearcher
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } },
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description("Search the web for information on a query. Returns titles, URLs, and snippets from search results.")]
    public async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var html = await Http.GetStringAsync(
                $"https://html.duckduckgo.com/html/?q={encoded}");

            var results = ParseDuckDuckGoResults(html);
            if (results.Count == 0)
                return "No search results found.";

            var sb = new StringBuilder();
            foreach (var (title, url, snippet) in results.Take(5))
            {
                sb.AppendLine($"Title: {title}");
                sb.AppendLine($"URL:   {url}");
                sb.AppendLine($"       {snippet}");
                sb.AppendLine();
            }
            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch and extract the main text content from a web page URL. Use this to read an article or page in detail.")]
    public async Task<string> FetchPageAsync(
        [Description("The full URL of the web page to fetch")] string url)
    {
        try
        {
            var html = await Http.GetStringAsync(url);
            var text = ExtractText(html);
            const int maxLength = 4000;
            return text.Length > maxLength
                ? text[..maxLength] + "\n\n[Content truncated at 4 000 chars]"
                : text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    // ── HTML parsing helpers ────────────────────────────────────────────────────

    private static List<(string Title, string Url, string Snippet)> ParseDuckDuckGoResults(
        string html)
    {
        var results = new List<(string, string, string)>();

        var titleRx = new Regex(
            @"<a[^>]+class=""result__a""[^>]*href=""([^""]*?)""[^>]*>(.*?)</a>",
            RegexOptions.Singleline);

        var snippetRx = new Regex(
            @"<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>",
            RegexOptions.Singleline);

        var titles = titleRx.Matches(html);
        var snippets = snippetRx.Matches(html);

        for (int i = 0; i < Math.Min(titles.Count, 8); i++)
        {
            var rawUrl = titles[i].Groups[1].Value;
            var title = StripHtml(titles[i].Groups[2].Value);
            var snippet = i < snippets.Count ? StripHtml(snippets[i].Groups[1].Value) : "";

            var actualUrl = ExtractRedirectUrl(rawUrl);
            if (!string.IsNullOrWhiteSpace(title))
                results.Add((title.Trim(), actualUrl, snippet.Trim()));
        }

        return results;
    }

    private static string ExtractRedirectUrl(string ddgUrl)
    {
        var match = Regex.Match(ddgUrl, @"uddg=([^&]+)");
        if (match.Success)
            return Uri.UnescapeDataString(match.Groups[1].Value);

        return ddgUrl.StartsWith("//") ? "https:" + ddgUrl : ddgUrl;
    }

    private static string StripHtml(string html)
    {
        var text = Regex.Replace(html, @"<[^>]+>", " ");
        text = WebUtility.HtmlDecode(text);
        return Regex.Replace(text, @"\s+", " ").Trim();
    }

    private static string ExtractText(string html)
    {
        var text = Regex.Replace(html,
            @"<(script|style)[^>]*>.*?</\1>", "",
            RegexOptions.Singleline | RegexOptions.IgnoreCase);

        text = Regex.Replace(text, @"<[^>]+>", " ");
        text = WebUtility.HtmlDecode(text);
        text = Regex.Replace(text, @"[ \t]+", " ");
        text = Regex.Replace(text, @"\n\s*\n+", "\n\n");
        return text.Trim();
    }
}

