    }

    private static string ExtractText(string html)
    {
        var text = Regex.Replace(html,
            @"<(script|style)[^>]*>.*?</\1>", "",
            RegexOptions.Singleline | RegexOptions.IgnoreCase);

        text = Regex.Replace(text, @"<[^>]+>", " ");
