 /// <summary>Provides web search and page-fetching capabilities.</summary>
 public sealed class WebSearcher
 {
     private static readonly HttpClient Http = new()
     {
         DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } },
         Timeout = TimeSpan.FromSeconds(15),
     };

     [Description("Search the web for information on a query. Returns titles, URLs, and snippets from search results.")]
     public async Task<string> SearchAsync(
         [Description("The search query")] string query)
     {
         try
         {
             var encoded = Uri.EscapeDataString(query);
             var html = await Http.GetStringAsync(
                 $"https://html.duckduckgo.com/html/?q={encoded}");

             var results = ParseDuckDuckGoResults(html);
             if (results.Count == 0)
                 return "No search results found.";

             var sb = new StringBuilder();
             foreach (var (title, url, snippet) in results.Take(5))
             {
                 sb.AppendLine($"Title: {title}");
                 sb.AppendLine($"URL:   {url}");
                 sb.AppendLine($"       {snippet}");
                 sb.AppendLine();
             }
             return sb.ToString();
         }
         catch (Exception ex)
         {
             return $"Search failed: {ex.Message}";
         }
     }

     [Description("Fetch and extract the main text content from a web page URL. Use this to read an article or page in detail.")]
     public async Task<string> FetchPageAsync(
         [Description("The full URL of the web page to fetch")] string url)
     {
         try
         {
             var html = await Http.GetStringAsync(url);
             var text = ExtractText(html);
             const int maxLength = 4000;
             return text.Length > maxLength
                 ? text[..maxLength] + "\n\n[Content truncated at 4 000 chars]"
                 : text;
         }
         catch (Exception ex)
         {
             return $"Failed to fetch page: {ex.Message}";
         }
     }

     // ── HTML parsing helpers ────────────────────────────────────────────────────

     private static List<(string Title, string Url, string Snippet)> ParseDuckDuckGoResults(
         string html)
     {
         var results = new List<(string, string, string)>();

         var titleRx = new Regex(
             @"<a[^>]+class=""result__a""[^>]*href=""([^""]*?)""[^>]*>(.*?)</a>",
             RegexOptions.Singleline);

         var snippetRx = new Regex(
             @"<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>",
             RegexOptions.Singleline);

         var titles = titleRx.Matches(html);
         var snippets = snippetRx.Matches(html);

         for (int i = 0; i < Math.Min(titles.Count, 8); i++)
         {
             var rawUrl = titles[i].Groups[1].Value;
             var title = StripHtml(titles[i].Groups[2].Value);
             var snippet = i < snippets.Count ? StripHtml(snippets[i].Groups[1].Value) : "";

             var actualUrl = ExtractRedirectUrl(rawUrl);
             if (!string.IsNullOrWhiteSpace(title))
                 results.Add((title.Trim(), actualUrl, snippet.Trim()));
         }

         return results;
     }

     private static string ExtractRedirectUrl(string ddgUrl)
     {
         var match = Regex.Match(ddgUrl, @"uddg=([^&]+)");
         if (match.Success)
             return Uri.UnescapeDataString(match.Groups[1].Value);

         return ddgUrl.StartsWith("//") ? "https:" + ddgUrl : ddgUrl;
     }

     private static string StripHtml(string html)
     {
         var text = Regex.Replace(html, @"<[^>]+>", " ");
         text = WebUtility.HtmlDecode(text);
         return Regex.Replace(text, @"\s+", " ").Trim();
     }

     private static string ExtractText(string html)
     {
         var text = Regex.Replace(html,
             @"<(script|style)[^>]*>.*?</\1>", "",
             RegexOptions.Singleline | RegexOptions.IgnoreCase);

         text = Regex.Replace(text, @"<[^>]+>", " ");
         text = WebUtility.HtmlDecode(text);
         text = Regex.Replace(text, @"[ \t]+", " ");
         text = Regex.Replace(text, @"\n\s*\n+", "\n\n");
         return text.Trim();
     }
